import React, { useState } from 'react';
import './App.css';

function App() {
  // משתני קלט (state)
  const [folder, setFolder] = useState('');
  const [key, setKey] = useState('');

  const runEncryption = async () => {
    if (!folder) return alert("יש להזין נתיב תיקייה");
    try {
      const response = await fetch("http://127.0.0.1:5000/encrypt", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ folder })
      });
      const result = await response.json();
      alert(`✅ סטטוס: ${result.status}\n📁 תיקייה: ${result.folder}`);
    } catch {
      alert("❌ שגיאה בחיבור לשרת");
    }
  };

  const runDecryption = async () => {
    if (!folder || !key) return alert("אנא מלא את שני השדות");
    try {
      const response = await fetch("http://127.0.0.1:5000/decrypt", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ folder, key })
      });
      const result = await response.json();
      alert(`✅ פוענח: ${result.folder}`);
    } catch {
      alert("❌ שגיאה בפיענוח");
    }
  };

  return (
    <div className="App">
      <div style={{ marginBottom: "20px" }}>
        <input
          type="text"
          value={folder}
          onChange={e => setFolder(e.target.value)}
          placeholder="📁 נתיב תיקייה"
          style={{ width: "300px", padding: "10px", marginRight: "10px" }}
        />
        <input
          type="text"
          value={key}
          onChange={e => setKey(e.target.value)}
          placeholder="🔑 מפתח HEX לפיענוח"
          style={{ width: "300px", padding: "10px" }}
        />
      </div>
      <div className="menu">
        <button onClick={runEncryption}>💣 הפעל הצפנה</button>
        <button onClick={runDecryption}>🔓 הפעל פיענוח</button>
      </div>
    </div>
  );
}

export default App;
